package com.example.orders.domain;

import org.springframework.data.mongodb.core.mapping.Document;

@Document("orders")
class OrderDocument {
    // Bad: missing unique/index strategy for lookup fields, missing @Id
    String orderNumber;
}

good-example.code-block:
package com.example.orders.service;

import com.example.orders.domain.OrderDocument;
import org.springframework.data.mongodb.repository.MongoRepository;
import org.springframework.stereotype.Service;
import java.util.Optional;

interface OrderRepository extends MongoRepository<OrderDocument, String> {
    Optional<OrderDocument> findByOrderNumber(String orderNumber);
}

@Service
class OrderService {
    private final OrderRepository repository;

    OrderService(OrderRepository repository) {
        this.repository = repository;
    }

    OrderDocument create(OrderDocument doc) {
        return repository.save(doc);
    }
}

