good-example.code-block:
package com.example.orders.service;

import com.example.orders.domain.OrderDocument;
import org.springframework.dao.DuplicateKeyException;
import org.springframework.dao.OptimisticLockingFailureException;
import org.springframework.stereotype.Service;

@Service
class OrderService {
    private final OrderRepository repository;

    OrderService(OrderRepository repository) {
        this.repository = repository;
    }

    OrderDocument create(OrderDocument doc) {
        try {
            return repository.save(doc);
        } catch (DuplicateKeyException ex) {
            throw new IllegalStateException("Order number already exists", ex);
        } catch (OptimisticLockingFailureException ex) {
            throw new IllegalStateException("Concurrent update detected", ex);
        }
    }
}

bad-example.code-block:
package com.example.orders.service;

import com.example.orders.domain.OrderDocument;
import org.springframework.stereotype.Service;

@Service
class BadOrderService {
    private final OrderRepository repository;

    BadOrderService(OrderRepository repository) {
        this.repository = repository;
    }

    OrderDocument create(OrderDocument doc) {
        try {
            return repository.save(doc);
        } catch (Exception ignored) {
            // Bad: hiding persistence failures makes debugging impossible
            return null;
        }
    }
}

